import{_ as n,o as h,c as a,a0 as i}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Mặt hàng","description":"","frontmatter":{"title":"Mặt hàng"},"headers":[],"relativePath":"item.md","filePath":"item.md"}'),o={name:"item.md"};function g(r,t,s,d,c,l){return h(),a("div",null,[...t[0]||(t[0]=[i(`<h1 id="mat-hang" tabindex="-1">Mặt hàng <a class="header-anchor" href="#mat-hang" aria-label="Permalink to &quot;Mặt hàng&quot;">​</a></h1><h2 id="mat-hang-la-gi" tabindex="-1">Mặt hàng là gì? <a class="header-anchor" href="#mat-hang-la-gi" aria-label="Permalink to &quot;Mặt hàng là gì?&quot;">​</a></h2><p><strong>Mặt hàng</strong> (Item) là sản phẩm hoặc dịch vụ mà doanh nghiệp của bạn mua, bán, hoặc sản xuất. Đây là một trong những danh mục dữ liệu quan trọng nhất trong ABNERP — hầu hết các giao dịch nghiệp vụ (bán hàng, mua hàng, sản xuất, kho vận) đều liên quan đến mặt hàng.</p><h2 id="phan-loai-mat-hang" tabindex="-1">Phân loại mặt hàng <a class="header-anchor" href="#phan-loai-mat-hang" aria-label="Permalink to &quot;Phân loại mặt hàng&quot;">​</a></h2><p>ABNERP hỗ trợ các loại mặt hàng sau:</p><table tabindex="0"><thead><tr><th>Loại mặt hàng</th><th>Mô tả</th><th>Ví dụ</th></tr></thead><tbody><tr><td><strong>Nguyên vật liệu</strong></td><td>Vật liệu thô dùng trong quá trình sản xuất</td><td>Vải, thép, nhựa, linh kiện điện tử</td></tr><tr><td><strong>Bán thành phẩm</strong></td><td>Sản phẩm đã qua một công đoạn sản xuất, cần gia công thêm</td><td>Vỏ điện thoại chưa lắp ráp, bánh đã nướng sẵn</td></tr><tr><td><strong>Thành phẩm</strong></td><td>Sản phẩm hoàn chỉnh sẵn sàng bán ra thị trường</td><td>Điện thoại, máy tính, bàn ghế</td></tr><tr><td><strong>Biến thể</strong></td><td>Các phiên bản khác nhau của cùng một mặt hàng gốc (kích thước, màu sắc)</td><td>Áo thun màu đỏ size XL, Áo thun màu xanh size M</td></tr><tr><td><strong>Dịch vụ</strong></td><td>Các dịch vụ cung cấp cho khách hàng</td><td>Tư vấn, bảo trì, vận chuyển, lắp đặt</td></tr><tr><td><strong>Bộ sản phẩm</strong></td><td>Nhóm sản phẩm được bán kèm với nhau</td><td>Combo văn phòng phẩm, giỏ quà tết</td></tr></tbody></table><h2 id="tao-mat-hang-moi" tabindex="-1">Tạo mặt hàng mới <a class="header-anchor" href="#tao-mat-hang-moi" aria-label="Permalink to &quot;Tạo mặt hàng mới&quot;">​</a></h2><h3 id="cac-buoc-thuc-hien" tabindex="-1">Các bước thực hiện <a class="header-anchor" href="#cac-buoc-thuc-hien" aria-label="Permalink to &quot;Các bước thực hiện&quot;">​</a></h3><ol><li>Truy cập <strong>Trang chủ &gt; Kho &gt; Mặt hàng</strong> (hoặc tìm kiếm &quot;Mặt hàng&quot; trên thanh tìm kiếm)</li><li>Nhấn <strong>+ Thêm Mặt hàng</strong></li><li>Điền thông tin chi tiết</li><li>Nhấn <strong>Lưu</strong></li></ol><h3 id="cac-truong-thong-tin-chinh" tabindex="-1">Các trường thông tin chính <a class="header-anchor" href="#cac-truong-thong-tin-chinh" aria-label="Permalink to &quot;Các trường thông tin chính&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Trường</th><th>Bắt buộc</th><th>Mô tả</th></tr></thead><tbody><tr><td><strong>Mã mặt hàng</strong></td><td>Có</td><td>Mã định danh duy nhất của mặt hàng (tự động sinh hoặc nhập thủ công)</td></tr><tr><td><strong>Tên mặt hàng</strong></td><td>Có</td><td>Tên hiển thị của mặt hàng</td></tr><tr><td><strong>Loại mặt hàng</strong></td><td>Có</td><td>Phân loại: Nguyên vật liệu, Bán thành phẩm, Thành phẩm, Dịch vụ, v.v.</td></tr><tr><td><strong>Đơn vị đo lường (UOM)</strong></td><td>Có</td><td>Đơn vị tính mặc định: cái, kg, mét, giờ, v.v.</td></tr><tr><td><strong>Nhóm mặt hàng</strong></td><td>Không</td><td>Phân nhóm để lọc và báo cáo (ví dụ: Điện tử, Thời trang)</td></tr><tr><td><strong>Giá bán mặc định</strong></td><td>Không</td><td>Giá niêm yết mặc định</td></tr><tr><td><strong>Giá mua mặc định</strong></td><td>Không</td><td>Giá nhập kho mặc định</td></tr><tr><td><strong>Mô tả</strong></td><td>Không</td><td>Mô tả chi tiết về mặt hàng</td></tr><tr><td><strong>Thuế</strong></td><td>Không</td><td>Thuế suất VAT áp dụng cho mặt hàng</td></tr><tr><td><strong>Hình ảnh</strong></td><td>Không</td><td>Hình ảnh minh họa cho mặt hàng</td></tr></tbody></table><h2 id="nhom-mat-hang" tabindex="-1">Nhóm mặt hàng <a class="header-anchor" href="#nhom-mat-hang" aria-label="Permalink to &quot;Nhóm mặt hàng&quot;">​</a></h2><p><strong>Nhóm mặt hàng</strong> (Item Group) giúp bạn phân loại và tổ chức danh mục mặt hàng theo cấu trúc cây. Ví dụ:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tất cả nhóm mặt hàng</span></span>
<span class="line"><span>├── Điện tử</span></span>
<span class="line"><span>│   ├── Điện thoại</span></span>
<span class="line"><span>│   ├── Máy tính</span></span>
<span class="line"><span>│   └── Phụ kiện</span></span>
<span class="line"><span>├── Thời trang</span></span>
<span class="line"><span>│   ├── Quần áo</span></span>
<span class="line"><span>│   └── Giày dép</span></span>
<span class="line"><span>└── Văn phòng phẩm</span></span>
<span class="line"><span>    ├── Giấy in</span></span>
<span class="line"><span>    ├── Bút viết</span></span>
<span class="line"><span>    └── Bàn ghế</span></span></code></pre></div><p>Bạn có thể tạo nhóm mặt hàng mới tại <strong>Trang chủ &gt; Kho &gt; Nhóm mặt hàng</strong>.</p><h2 id="đon-vi-tinh" tabindex="-1">Đơn vị tính <a class="header-anchor" href="#đon-vi-tinh" aria-label="Permalink to &quot;Đơn vị tính&quot;">​</a></h2><p><strong>Đơn vị đo lường</strong> (Unit of Measure - UOM) xác định cách tính số lượng của mặt hàng. Một mặt hàng có thể có nhiều đơn vị tính chuyển đổi qua lại. Ví dụ:</p><table tabindex="0"><thead><tr><th>Mặt hàng</th><th>Đơn vị cơ bản</th><th>Đơn vị chuyển đổi</th><th>Tỷ lệ</th></tr></thead><tbody><tr><td>Gạo</td><td>kg</td><td>tạ</td><td>1 tạ = 100 kg</td></tr><tr><td>Nước ngọt</td><td>lon</td><td>thùng</td><td>1 thùng = 24 lon</td></tr><tr><td>Vải</td><td>mét</td><td>cuộn</td><td>1 cuộn = 50 mét</td></tr></tbody></table><p>Để thiết lập chuyển đổi đơn vị tính, vào <strong>Trang chủ &gt; Kho &gt; Chuyển đổi đơn vị tính</strong> hoặc cấu hình trực tiếp trong form mặt hàng.</p><h2 id="bien-the-mat-hang" tabindex="-1">Biến thể mặt hàng <a class="header-anchor" href="#bien-the-mat-hang" aria-label="Permalink to &quot;Biến thể mặt hàng&quot;">​</a></h2><p>Biến thể (Item Variant) cho phép bạn tạo nhiều phiên bản của cùng một mặt hàng gốc dựa trên các thuộc tính. Ví dụ:</p><ul><li><strong>Áo sơ mi</strong>: Màu sắc (trắng, xanh, đen), Kích cỡ (S, M, L, XL)</li><li><strong>Bàn gỗ</strong>: Chất liệu (gỗ sồi, gỗ óc chó), Kích thước (1.2m, 1.6m, 2m)</li></ul><p>Cách tạo biến thể:</p><ol><li>Tạo mặt hàng gốc (Template Item)</li><li>Đánh dấu <strong>Có biến thể</strong> (Has Variants)</li><li>Định nghĩa các thuộc tính biến thể (Item Attributes)</li><li>Hệ thống tự động tạo các biến thể dựa trên tổ hợp thuộc tính</li></ol><h2 id="quan-ly-ton-kho-theo-mat-hang" tabindex="-1">Quản lý tồn kho theo mặt hàng <a class="header-anchor" href="#quan-ly-ton-kho-theo-mat-hang" aria-label="Permalink to &quot;Quản lý tồn kho theo mặt hàng&quot;">​</a></h2><p>Sau khi tạo mặt hàng, bạn có thể:</p><ul><li><strong>Nhập kho</strong>: Tăng số lượng tồn kho</li><li><strong>Xuất kho</strong>: Giảm số lượng tồn kho</li><li><strong>Chuyển kho</strong>: Di chuyển hàng giữa các kho</li><li><strong>Kiểm kê</strong>: Điều chỉnh số lượng thực tế</li><li><strong>Theo dõi lịch sử</strong>: Xem nhật ký nhập xuất của từng mặt hàng</li></ul><h2 id="meo-va-luu-y" tabindex="-1">Mẹo và lưu ý <a class="header-anchor" href="#meo-va-luu-y" aria-label="Permalink to &quot;Mẹo và lưu ý&quot;">​</a></h2><ul><li>Sử dụng mã mặt hàng có cấu trúc (ví dụ: SP-001, NVL-002) để dễ quản lý</li><li>Thiết lập nhóm mặt hàng ngay từ đầu để dễ dàng lọc và báo cáo sau này</li><li>Với mặt hàng có nhiều đơn vị tính, hãy thiết lập chuyển đổi để hệ thống tự động quy đổi khi nhập xuất</li><li>Kích hoạt tính năng <strong>Theo dõi số lô</strong> (Serial Number) hoặc <strong>Theo dõi lô</strong> (Batch) cho mặt hàng cần quản lý đặc biệt</li></ul>`,29)])])}const u=n(o,[["render",g]]);export{m as __pageData,u as default};
